// FFmpeg drawtext 텍스트 이스케이프
function esc(text) {
  return (text || '')
    .replace(/\\/g, '')
    .replace(/'/g, '\u2019')
    .replace(/;/g, '')
    .replace(/%/g, '%%');
}

// ── 상단 제목 처리 ──
