 * 수동 실행이면 빈 배열 반환
 */
let productionId = '';
// Webhook 우선
try {
  const wh = $('Webhook').first().json;
  productionId = (wh.body && wh.body.productionId) || wh.productionId || '';
} catch (_) {}
