if (!productionId) {
  try {
    const triggerData = $('Execute Workflow Trigger').first().json;
    productionId = triggerData.productionId || '';
  } catch (_) {}
}
if (!productionId) return [{ json: { skipped: true, status: 'no_productionId' } }];
return [{ json: { productionId, status: 'rendering' } }];

/**
