// 카테고리 + 주제 순서 선택 (staticData로 상태 유지)
const staticData = $getWorkflowStaticData('global');
if (typeof staticData.categoryIndex !== 'number') staticData.categoryIndex = 0;
if (!staticData.topicIndices) staticData.topicIndices = {0:0, 1:0, 2:0, 3:0};

const categories = [
  { index: 1, name: '먹튀검증/안전 정보', count: 7, topics: [
    '1. 먹튀 사이트 구별하는 핵심 체크포인트 3가지',
    '2. 안전한 카지노 사이트 고르는 법',
    '3. 먹튀 당했을 때 대처법 (신고, 증거 수집)',
    '4. 메이저사이트 vs 신생사이트 차이점',
    '5. 먹튀검증 제대로 하는 법',
    '6. 먹튀제보/먹튀검증 사례와 피하는 법',
    '7. 메이저사이트 vs 먹튀사이트 구별법'
  ]},
  { index: 2, name: '카지노/게임 팁', count: 7, topics: [
    '8. 슬롯 초보가 꼭 알아야 할 기본 상식',
    '9. 라이브 카지노 처음 할 때 실수하기 쉬운 것들',
    '10. 환전 시 주의사항 (수수료, 시간, 한도)',
    '11. 보너스/이벤트 제대로 활용하는 법',
    '12. 배팅 자금 관리의 기본',
    '13. 잭팟 제보와 현실적 확률, 터진 후기',
    '14. 무료슬롯 체험 - 입금 전에 먼저 체험하는 팁'
  ]},
  { index: 3, name: '커뮤니티 활용', count: 7, topics: [
    '15. 온카스터디 포인트 꿀팁 (복권, 돌림판, 오목, 무료슬롯)',
    '16. 제휴사이트 후기 읽는 법 (진짜 후기 vs 광고)',
    '17. 제휴사이트 후기 - 검증된 사이트 고르는 기준',
    '18. 자유게시판에서 정보 얻는 팁',
    '19. 방송존 활용법 (동물원, 가디언, 인생역전, 하이라이트)',
    '20. 기프티콘 교환 꿀팁',
    '21. 패널티명단 - 사기꾼/양아치 구별법'
  ]},
  { index: 4, name: '스포츠/분석', count: 6, topics: [
    '22. 스포츠 배팅 기초',
    '23. 스포츠 분석/배팅 - 분석 없이 배팅하는 위험성',
    '24. 스포츠 뉴스 해석하는 법',
    '25. 라이브 스코어 활용법',
    '26. 배당률 읽는 법 (초보 가이드)',
    '27. 스포츠 분석 게시판 활용 팁'
  ]}
];

const catIdx = staticData.categoryIndex % 4;
const cat = categories[catIdx];
const topicIdx = (staticData.topicIndices[catIdx] || 0) % cat.topics.length;
const currentTopic = cat.topics[topicIdx];

console.log('카테고리: ' + cat.name + ', 주제: ' + currentTopic);

// 다음 실행을 위해 업데이트
staticData.topicIndices[catIdx] = topicIdx + 1;
staticData.categoryIndex++;

return [{ json: {
  categoryIndex: cat.index,
  categoryName: cat.name,
  topicNumber: topicIdx + 1,
  currentTopic: currentTopic
}}];

// 영상3 실패/타임아웃 체크 (원본 이미지 폴백)
const staticData = $getWorkflowStaticData('node');
if (!staticData.retryCount) staticData.retryCount = 0;
staticData.retryCount++;

const data = $input.first().json;
const flag = data?.data?.successFlag;
const originalImageUrl = $('이미지 URL 추출').first().json?.images?.[0]?.url || '';

// successFlag === 1 → 성공
if (flag === 1) {
  staticData.retryCount = 0;
  return [{json: data}];
}

// successFlag >= 2 또는 재시도 20회 초과 → 원본 이미지 폴백
if ((typeof flag === 'number' && flag >= 2) || staticData.retryCount > 20) {
  const reason = (typeof flag === 'number' && flag >= 2)
    ? '영상3 실패 (successFlag=' + flag + ')'
    : '영상3 타임아웃 (' + staticData.retryCount + '회)';
  console.log(reason + ' → 원본 이미지 폴백');
  staticData.retryCount = 0;
  const mod = JSON.parse(JSON.stringify(data));
  mod.data = mod.data || {};
  mod.data.successFlag = 1;
  mod.videoFailed = true;
  mod.failReason = reason;
  mod.originalImageUrl = originalImageUrl;
  return [{json: mod}];
