const refB_url = refResults[1]?.json?.refUrl || '';

if (!refA_url || !refB_url) {
  throw new Error('참조 이미지 URL 없음! refA=' + !!refA_url + ', refB=' + !!refB_url);
}

// Veo3 핑퐁 대화 프롬프트 생성
function buildVeo3Dialogue(turns) {
  const speakerDesc = {
    'A': 'The elderly Korean grandmother (silver-gray permed short hair, floral pattern vest, reading glasses)',
    'B': 'The young Black man (medium twists hairstyle, white graphic t-shirt, silver watch)'
  };

  return turns.map((turn, i) => {
    const desc = speakerDesc[turn.speaker] || speakerDesc['A'];
    const line = turn.line.replace(/'/g, "");
    if (i === 0) return desc + " says '" + line + "'";
    return "then " + desc + " responds '" + line + "'";
  }).join(', ');
}

return scenes.map((scene, i) => {
  const speaker = scene.speaker || scene.dialogue_turns?.[0]?.speaker || 'A';

  const cleanImagePrompt = scene.image_prompt.replace(/"/g, "'");

  // dialogue_turns 핑퐁 프롬프트
  let dialoguePart;
  if (scene.dialogue_turns && scene.dialogue_turns.length > 1) {
    dialoguePart = buildVeo3Dialogue(scene.dialogue_turns);
  } else {
    const cleanDialogue = scene.dialogue.replace(/"/g, "'");
    dialoguePart = 'The person is naturally speaking in Korean, saying: ' + cleanDialogue;
  }

  const veo3_prompt = cleanImagePrompt +
    '. ' + dialoguePart +
    '. Natural back-and-forth conversation with realistic timing. Natural lip synchronization for both speakers, subtle body gestures while talking, cinematic camera movement. No text overlay, no subtitles, no captions on screen.';

  return {
    json: {
      index: i,
      dialogue: scene.dialogue,
      dialogue_turns: scene.dialogue_turns || [{speaker: speaker, line: scene.dialogue}],
      image_prompt: scene.image_prompt,
      veo3_prompt: veo3_prompt,
      speaker: speaker,
      refUrl_A: refA_url,
      refUrl_B: refB_url,
    }
  };
});

const raw = $input.first().json;
let text = '';
if (raw.content && raw.content.parts) {
  text = raw.content.parts[0].text;
} else if (typeof raw === 'string') {
  text = raw;
} else if (raw.text) {
  text = raw.text;
} else {
  text = JSON.stringify(raw);
}

const cleanText = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
const data = JSON.parse(cleanText);

if (!data.scenes || data.scenes.length < 3) {
  throw new Error('scenes must have at least 3 items, got: ' + (data.scenes?.length || 0));
}

// dialogue_turns 검증
for (let i = 0; i < data.scenes.length; i++) {
  const scene = data.scenes[i];
  if (!scene.dialogue_turns || scene.dialogue_turns.length < 2) {
    if (scene.dialogue && scene.speaker) {
      scene.dialogue_turns = [{speaker: scene.speaker, line: scene.dialogue}];
    } else {
      throw new Error('scene ' + (i+1) + ' missing dialogue_turns');
    }
  }
  if (!scene.dialogue) {
    scene.dialogue = scene.dialogue_turns.map(t => t.line).join(' ');
  }
  if (!scene.speaker) {
    scene.speaker = scene.dialogue_turns[0].speaker;
  }
}

return [{
  json: {
    hook_title: data.hook_title,
    scenes: data.scenes,
    Subject: data.Subject,
    Caption: data.Caption,
    Comment: data.Comment,
    BGM_prompt: data.BGM_prompt,
    fullDialogue: data.scenes.map(s => s.dialogue).join(' '),
    segmentCount: data.scenes.length,
    Status: '준비',
    generatedAt: new Date().toISOString()
  }
}];

// 16:9 → 9:16 숏츠 변환 + 제목/자막 오버레이
const prevData = $input.first().json;
const videoUrl = prevData.final_video_url || prevData.url || '';

if (!videoUrl) {
  return [{ json: { ...prevData, convertSkipped: true } }];
}

const fontBold = '/usr/share/fonts/truetype/nanum/NanumGothicBold.ttf';
const fontRegular = '/usr/share/fonts/truetype/nanum/NanumGothic.ttf';

// FFmpeg drawtext 텍스트 이스케이프
function esc(text) {
  return (text || '')
    .replace(/\\/g, '')
    .replace(/'/g, '\u2019')
    .replace(/;/g, '')
    .replace(/%/g, '%%');
}

// ── 상단 제목 처리 ──
let title = (prevData.hookTitle || '').replace(/<\/?y>/g, '');

// 제목 줄바꿈 (12자 초과 시 2줄)
function splitTitle(text) {
  if (text.length <= 13) return [text];
  const mid = Math.ceil(text.length / 2);
  let splitIdx = -1;
  for (let d = 0; d <= 6; d++) {
    for (const offset of [-d, d]) {
      const i = mid + offset;
      if (i >= 0 && i < text.length && ' :,!?·'.includes(text[i])) {
        splitIdx = text[i] === ' ' ? i : i + 1;
        break;
      }
    }
    if (splitIdx !== -1) break;
  }
  if (splitIdx === -1) splitIdx = mid;
  return [text.substring(0, splitIdx).trim(), text.substring(splitIdx).trim()].filter(Boolean);
}

const titleLines = splitTitle(title);

// ── 필터 빌드 ──
let f = '[0:v]scale=1080:-2,pad=1080:1920:(ow-iw)/2:(oh-ih)/2:black';

// 상단 제목
const titleFontSize = 80;
const titleLineH = 95;
const titleStartY = titleLines.length === 1 ? 280 : 250;

for (let i = 0; i < titleLines.length; i++) {
  const y = titleStartY + (i * titleLineH);
  f += ",drawtext=text='" + esc(titleLines[i]) + "'"
    + ':fontfile=' + fontBold
    + ':fontsize=' + titleFontSize
    + ':fontcolor=white'
    + ':x=(w-text_w)/2'
    + ':y=' + y
    + ':borderw=4:bordercolor=black';
}

// 하단 자막 (턴별 타이밍, 긴 대사 2줄 분리)
const dialogueData = prevData.dialogueData || [];
const subtitleFontSize = 48;
const subtitleLineH = 62;
const maxCharsPerLine = 14;

// 긴 대사를 2줄로 분리
function splitSubtitle(text) {
  if (text.length <= maxCharsPerLine) return [text];
  const mid = Math.ceil(text.length / 2);
  let splitIdx = -1;
  for (let d = 0; d <= 5; d++) {
    for (const offset of [-d, d]) {
      const i = mid + offset;
      if (i >= 0 && i < text.length && ' ,!?.·'.includes(text[i])) {
        splitIdx = text[i] === ' ' ? i : i + 1;
        break;
      }
    }
    if (splitIdx !== -1) break;
  }
  if (splitIdx === -1) splitIdx = mid;
  return [text.substring(0, splitIdx).trim(), text.substring(splitIdx).trim()].filter(Boolean);
}

for (const seg of dialogueData) {
  const turns = seg.turns || [];
  if (turns.length === 0) continue;
  const turnDur = seg.duration / turns.length;

  for (let j = 0; j < turns.length; j++) {
    const text = esc(turns[j].line || '');
    if (!text) continue;
    const tStart = (seg.start + j * turnDur).toFixed(2);
    const tEnd = (seg.start + (j + 1) * turnDur).toFixed(2);
    const lines = splitSubtitle(text);

    // 줄 수에 따라 Y 위치 조정 (2줄이면 위로 올림)
    const baseY = lines.length === 1 ? 1400 : 1370;

    for (let k = 0; k < lines.length; k++) {
      const y = baseY + (k * subtitleLineH);
      f += ",drawtext=text='" + esc(lines[k]) + "'"
        + ':fontfile=' + fontBold
        + ':fontsize=' + subtitleFontSize
        + ':fontcolor=white'
        + ':x=(w-text_w)/2'
        + ':y=' + y
        + ':borderw=3:bordercolor=black'
        + ":enable='between(t," + tStart + "," + tEnd + ")'";
    }
  }
}

f += '[vout]';

try {
  const result = await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://76.13.182.180:8080/v1/ffmpeg/compose',
    headers: {
      'x-api-key': 'nca-sagong-2026',
      'Content-Type': 'application/json'
    },
    body: {
      inputs: [{ file_url: videoUrl }],
      filters: [{ filter: f }],
      outputs: [{
        options: [
          { option: '-map', argument: '[vout]' },
          { option: '-map', argument: '0:a' },
          { option: '-c:v', argument: 'libx264' },
          { option: '-preset', argument: 'medium' },
          { option: '-crf', argument: '18' },
          { option: '-c:a', argument: 'aac' },
          { option: '-b:a', argument: '256k' },
          { option: '-pix_fmt', argument: 'yuv420p' },
          { option: '-movflags', argument: '+faststart' }
        ],
        file_name: 'story_shorts_9x16.mp4'
      }]
    }
  });

  return [{ json: { ...prevData, convertResult: result, originalVideoUrl: videoUrl, filterUsed: f } }];
} catch (e) {
  console.log('9:16 변환 실패: ' + e.message);
  return [{ json: { ...prevData, convertError: e.message } }];
}

// 9:16 변환 결과 처리
const prevData = $input.first().json;

// 변환 스킵 또는 에러 시 원본 유지
if (prevData.convertSkipped || prevData.convertError) {
  return [{ json: {
    final_video_url: prevData.final_video_url || prevData.url,
    url: prevData.final_video_url || prevData.url,
    srtContent: prevData.srtContent,
    subject: prevData.subject,
    caption: prevData.caption,
    comment: prevData.comment,
  }}];
}

const convertResult = prevData.convertResult || {};
let shortsUrl = '';

if (Array.isArray(convertResult.response)) {
  shortsUrl = convertResult.response[0]?.file_url || '';
} else if (convertResult.file_url) {
  shortsUrl = convertResult.file_url;
} else if (typeof convertResult.response === 'string') {
  shortsUrl = convertResult.response;
}

const finalUrl = shortsUrl || prevData.final_video_url || prevData.url;

return [{
  json: {
    final_video_url: finalUrl,
    url: finalUrl,
    originalVideoUrl: prevData.originalVideoUrl || prevData.final_video_url,
    srtContent: prevData.srtContent,
    subject: prevData.subject,
    caption: prevData.caption,
    comment: prevData.comment,
    isShorts: !!shortsUrl
  }
}];
